#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        int found = 0;
        for(int i=0;i<N;++i){
            int v; scanf("%d", &v);
            if(v == X) found = 1;
        }
        printf(found ? "YES\n" : "NO\n");
    }
    return 0;
}

